class Solution(object):
    def maximumLength(self, nums, k):
        # dp[i][j] = max length of good subsequence ending at index i with exactly j transitions
        # Transition: dp[i][j] = max over all prev where nums[prev] != nums[i]: dp[prev][j-1] + 1
        #                        max over all prev where nums[prev] == nums[i]: dp[prev][j] + 1
        # Use: for each (val, transitions_used), track best length
        from collections import defaultdict
        # best[j][v] = max dp length ending with value v using j transitions
        best = defaultdict(lambda: defaultdict(int))
        ans = 1
        for v in nums:
            for j in range(k, -1, -1):
                # Extend from same value (no new transition)
                new_len = best[j][v] + 1
                # Extend from different value (new transition), need j >= 1
                if j > 0:
                    # max over all other values = global max at j-1 minus same-value constraint
                    # Track top-2 values
                    pass
                best[j][v] = max(best[j][v], new_len)
                ans = max(ans, new_len)
        # Simpler O(n^2 * k) approach for n<=500, k<=25
        n = len(nums)
        dp = [[0] * (k+1) for _ in range(n)]
        for i in range(n):
            for j in range(k+1):
                dp[i][j] = 1
        for i in range(n):
            for prev in range(i):
                if nums[prev] == nums[i]:
                    for j in range(k+1):
                        dp[i][j] = max(dp[i][j], dp[prev][j] + 1)
                else:
                    for j in range(1, k+1):
                        dp[i][j] = max(dp[i][j], dp[prev][j-1] + 1)
        return max(dp[i][j] for i in range(n) for j in range(k+1))
